//! Binary to encode PISA posting lists with Elias-Fano encoding.
//!
//! Usage:
//!   cargo run --release --bin encode_pisa -- <input.docs> [--remap <mapping_file>]
//!
//! The PISA format is:
//!   - Header: 2 x u32 (typically [1, num_documents])
//!   - For each posting list:
//!     - u32: length of the posting list
//!     - length x u32: document IDs (d-gaps, i.e., delta encoded)
//!
//! The optional --remap argument specifies a binary file containing a mapping
//! from old doc IDs to new doc IDs (generated by reorder_docids).

use std::collections::HashMap;
use std::env;
use std::fs::File;
use std::io::{BufReader, Read, Write};
use std::path::Path;
use std::time::Instant;

use pef::optimal_bits_per_value;

/// Read a u32 from a reader (little-endian)
fn read_u32<R: Read>(reader: &mut R) -> std::io::Result<u32> {
    let mut buf = [0u8; 4];
    reader.read_exact(&mut buf)?;
    Ok(u32::from_le_bytes(buf))
}

/// Read a posting list from PISA format
fn read_posting_list<R: Read>(reader: &mut R) -> std::io::Result<Option<Vec<u32>>> {
    let mut len_buf = [0u8; 4];
    match reader.read_exact(&mut len_buf) {
        Ok(_) => {}
        Err(e) if e.kind() == std::io::ErrorKind::UnexpectedEof => return Ok(None),
        Err(e) => return Err(e),
    }
    let len = u32::from_le_bytes(len_buf) as usize;

    let mut postings = vec![0u32; len];
    for posting in &mut postings {
        *posting = read_u32(reader)?;
    }
    Ok(Some(postings))
}

/// Statistics about the encoding
#[derive(Default)]
struct Stats {
    num_lists: u64,
    total_postings: u64,
    total_input_bytes: u64,
    total_ef_bytes: u64,
    total_gef_bytes: u64,
    total_pef_bytes: u64,
    total_vbyte_bytes: u64,
    total_bp128_bytes: u64,
    total_bp32_bytes: u64,
    lists_by_size: [u64; 7], // 1, 2-10, 11-100, 101-1000, 1001-10000, 10001-100000, >100000
    // For entropy calculation
    dgap_counts: HashMap<u32, u64>,
    total_dgaps: u64,
}

/// Compute grouped Elias-Fano encoding size (partitioned EF).
fn grouped_elias_fano_bits(postings: &[u32]) -> u32 {
    let mut start = 0;
    let mut total = 0;
    const LIMIT: u32 = 32 * 8;
    let mut offset = 0;
    let mut skiplist = vec![];
    while start < postings.len() {
        let mut end = start + 1;
        let mut next_bits = 0;
        while end < postings.len() {
            offset = postings[start];
            let max = postings[end] - offset + 1;
            let len = (end - start) as u32;
            next_bits = 5 + optimal_bits_per_value(max - len, len).0;
            if next_bits > LIMIT {
                next_bits = LIMIT;
                break;
            }
            end += 1;
        }
        total += next_bits.div_ceil(8) * 8;
        start = end;
        if end < postings.len() {
            offset = postings[end];
            skiplist.push(offset);
        }
    }
    total
        + optimal_bits_per_value(
            skiplist.last().copied().unwrap_or_default() + 1 - skiplist.len() as u32,
            skiplist.len() as u32,
        )
        .0
}

/// Compute partitioned Elias-Fano encoding size.
/// Uses fixed-size partitions (like PISA's PEF implementation).
/// Each partition stores elements using standard EF relative to partition start.
/// Partition endpoints are stored in a top-level EF structure.
fn partitioned_elias_fano_bits(postings: &[u32], partition_size: usize) -> u64 {
    if postings.is_empty() {
        return 0;
    }
    if postings.len() <= partition_size {
        // Single partition - just use standard EF
        return optimal_bits_per_value(
            postings.last().copied().unwrap_or_default() + 1 - postings.len() as u32,
            postings.len() as u32,
        )
        .0 as u64;
    }

    let num_partitions = postings.len().div_ceil(partition_size);
    let mut total_bits: u64 = 0;
    let mut partition_endpoints = Vec::with_capacity(num_partitions);
    let mut bit_endpoints = Vec::with_capacity(num_partitions);

    // Encode each partition
    for (i, chunk) in postings.chunks(partition_size).enumerate() {
        let base = if i == 0 {
            0
        } else {
            postings[i * partition_size - 1] + 1
        };
        let max_in_partition = chunk.last().copied().unwrap_or(base) - base;
        let n = chunk.len() as u32;

        // Standard EF for this partition: n * (2 + log2(u/n)) where u = max - base + 1
        let partition_bits = optimal_bits_per_value(max_in_partition + 1 - n, n).0;
        total_bits += partition_bits as u64;

        // Store endpoint for skip list
        partition_endpoints.push(*chunk.last().unwrap());
        bit_endpoints.push(total_bits as u32);
    }

    // Add skip list overhead (endpoints encoded with EF)
    let skip_bits = optimal_bits_per_value(
        partition_endpoints.last().copied().unwrap_or_default() + 1 - num_partitions as u32,
        num_partitions as u32,
    )
    .0;
    total_bits += skip_bits as u64;
    let offset_bits = optimal_bits_per_value(
        bit_endpoints.last().copied().unwrap_or_default() + 1 - num_partitions as u32,
        num_partitions as u32,
    )
    .0;
    total_bits += offset_bits as u64;

    // Add partition size metadata (log2(partition_size) bits per partition boundary)
    // In practice, PISA uses fixed sizes so this is minimal
    total_bits += (num_partitions * 8) as u64; // ~1 byte per partition for metadata

    total_bits
}

/// Compute bit-packed encoded size for a posting list (d-gaps)
/// Packs `group_size` integers at a time with bit-packing.
/// Each block uses: 1 byte for bit-width + group_size * bit_width / 8 bytes
/// Leftover integers are stored as raw u32.
fn bitpacked_size(postings: &[u32], group_size: usize) -> u64 {
    if postings.is_empty() {
        return 0;
    }

    let mut total = 0u64;
    let mut prev = 0u32;
    let mut gaps = Vec::with_capacity(postings.len());

    // Compute d-gaps
    for &doc in postings {
        gaps.push(doc - prev);
        prev = doc;
    }

    // Process blocks of group_size
    let mut i = 0;
    while i + group_size <= gaps.len() {
        let block = &gaps[i..i + group_size];
        let max_gap = block.iter().copied().max().unwrap_or(0);
        let bit_width = if max_gap == 0 {
            0
        } else {
            32 - max_gap.leading_zeros()
        };
        // 1 byte for bit-width descriptor + packed data
        total += 1 + (group_size as u64 * bit_width as u64).div_ceil(8);
        i += group_size;
    }

    // Leftover integers stored as raw u32
    let leftover = gaps.len() - i;
    total += (leftover * 4) as u64;

    total
}

/// Compute VByte encoded size for a posting list (d-gaps)
fn vbyte_size(postings: &[u32]) -> u64 {
    if postings.is_empty() {
        return 0;
    }
    let mut total = 0u64;
    let mut prev = 0u32;
    for &doc in postings {
        let gap = doc - prev;
        prev = doc;
        // VByte: 7 bits per byte, continue bit in MSB
        total += match gap {
            0..=127 => 1,
            128..=16383 => 2,
            16384..=2097151 => 3,
            2097152..=268435455 => 4,
            _ => 5,
        };
    }
    total
}

/// Load a docid mapping file (binary array of (doc_id, parent_id))
/// Returns (old_to_new, subtree_ends)
fn load_mapping<P: AsRef<Path>>(path: P) -> std::io::Result<(Vec<u32>, Vec<u32>)> {
    let file = File::open(path)?;
    let file_len = file.metadata()?.len() as usize;
    let num_docs = file_len / 8; // 2 * u32

    let mut reader = BufReader::new(file);
    let mut old_to_new = vec![0u32; num_docs];
    let mut parents = vec![0u32; num_docs];

    // Read mapping and build old_to_new + parents (in new ID space)
    // The file is ordered by new_id (0..N-1)
    for new_id in 0..num_docs {
        let old_id = read_u32(&mut reader)?;
        let old_parent = read_u32(&mut reader)?;

        if old_id as usize >= num_docs {
            return Err(std::io::Error::new(
                std::io::ErrorKind::InvalidData,
                "Doc ID out of range",
            ));
        }
        old_to_new[old_id as usize] = new_id as u32;

        // We can't resolve old_parent to new_parent yet because we might not have seen old_parent yet.
        // So we store old_parent temporarily or do a second pass?
        // Actually, we can just store the old_parent for now, but we need to map it later.
        // But wait, we can't store old_parent in `parents` if we want `parents` to be new_ids.
        // Let's store old_parent in a temporary vector.
        parents[new_id] = old_parent;
    }

    // Convert parents to new IDs
    for parent in &mut parents {
        *parent = old_to_new[*parent as usize];
    }

    // Compute subtree ranges
    // In DFS order, children are visited after parents? No.
    // In DFS order:
    //   Visit u
    //   Visit children...
    // So u < child.
    // And the subtree of u is a contiguous range [u, end].
    // We can compute end by iterating backwards.
    let mut subtree_ends: Vec<u32> = (0..num_docs as u32).collect();

    for i in (1..num_docs).rev() {
        let u = i as u32;
        let p = parents[i];
        // If p is actually the parent (and not self-loop for root), propagate range
        if p != u {
            // The parent's range must include the child's range.
            // Since it's DFS, p < u.
            // And since we iterate backwards, we have already computed the full range of u.
            // So we extend p's range to include u's range.
            if subtree_ends[u as usize] > subtree_ends[p as usize] {
                subtree_ends[p as usize] = subtree_ends[u as usize];
            }
        }
    }

    Ok((old_to_new, subtree_ends))
}

/// Transform a posting list using the range toggle logic.
/// Returns the transformed posting list.
fn transform_posting_list(postings: &[u32], num_docs: usize, subtree_ends: &[u32]) -> Vec<u32> {
    let mut output = Vec::new();
    let mut stack: Vec<u32> = Vec::new(); // Stack of end positions

    // Use a cursor for the sorted postings to avoid O(N) lookup
    let mut posting_idx = 0;

    for i in 0..num_docs as u32 {
        // Check for expired ranges
        while let Some(&end) = stack.last() {
            if end < i {
                stack.pop();
            } else {
                break;
            }
        }
        let current_state = stack.len() % 2 != 0;

        // Check if current doc is in the posting list
        let is_present = if posting_idx < postings.len() && postings[posting_idx] == i {
            posting_idx += 1;
            true
        } else {
            false
        };

        if is_present != current_state {
            output.push(i);
            stack.push(subtree_ends[i as usize]);
        }
    }

    output
}

impl Stats {
    fn add_list(&mut self, postings: &[u32]) {
        let len = postings.len();
        self.num_lists += 1;
        self.total_postings += len as u64;
        self.total_input_bytes += (len * 4) as u64;

        // Compute standard Elias-Fano encoding size
        // Encode the inverse if it's smaller.
        let last_posting = postings.last().copied().unwrap_or_default() + 1;
        let ef_bits = if last_posting - len as u32 > len as u32 {
            optimal_bits_per_value(last_posting - len as u32, len as u32)
        } else {
            optimal_bits_per_value(len as u32, last_posting - len as u32)
        }
        .0;
        self.total_ef_bytes += ef_bits.div_ceil(8) as u64;

        // Compute grouped Elias-Fano encoding size
        let gef_bits = grouped_elias_fano_bits(postings);
        self.total_gef_bytes += gef_bits.div_ceil(8) as u64;

        // Compute partitioned Elias-Fano encoding size (64 elements per partition)
        let pef_bits = partitioned_elias_fano_bits(postings, 64);
        self.total_pef_bytes += pef_bits.div_ceil(8);

        // Compute VByte encoding size
        self.total_vbyte_bytes += vbyte_size(postings);

        // Compute BP128 encoding size
        self.total_bp128_bytes += bitpacked_size(postings, 128);

        // Compute BP32 encoding size
        self.total_bp32_bytes += bitpacked_size(postings, 32);

        // Track d-gap frequencies for entropy calculation
        let mut prev = 0u32;
        for &doc in postings {
            let gap = doc - prev;
            *self.dgap_counts.entry(gap).or_insert(0) += 1;
            self.total_dgaps += 1;
            prev = doc;
        }

        let bucket = match len {
            1 => 0,
            2..=10 => 1,
            11..=100 => 2,
            101..=1000 => 3,
            1001..=10000 => 4,
            10001..=100000 => 5,
            _ => 6,
        };
        self.lists_by_size[bucket] += 1;
    }

    /// Compute Shannon entropy of d-gaps in bits per symbol.
    fn compute_entropy(&self) -> f64 {
        if self.total_dgaps == 0 {
            return 0.0;
        }

        let n = self.total_dgaps as f64;
        let mut entropy = 0.0;

        for &count in self.dgap_counts.values() {
            if count > 0 {
                let p = count as f64 / n;
                entropy -= p * p.log2();
            }
        }

        entropy
    }

    fn print(&self) {
        println!("\n=== Encoding Statistics ===");
        println!("Total posting lists: {:>12}", self.num_lists);
        println!("Total postings:      {:>12}", self.total_postings);
        println!("Unique d-gap values: {:>12}", self.dgap_counts.len());
        println!();
        println!("List size distribution:");
        let buckets = [
            "1", "2-10", "11-100", "101-1K", "1K-10K", "10K-100K", ">100K",
        ];
        for (i, &name) in buckets.iter().enumerate() {
            let count = self.lists_by_size[i];
            let pct = 100.0 * count as f64 / self.num_lists as f64;
            println!("  {:>10}: {:>10} ({:>5.1}%)", name, count, pct);
        }
        println!();
        println!("Space usage:");
        println!(
            "  Input (raw u32):   {:>10} bytes ({:>6.2} MB)",
            self.total_input_bytes,
            self.total_input_bytes as f64 / 1_000_000.0
        );
        println!(
            "  Elias-Fano:        {:>10} bytes ({:>6.2} MB)",
            self.total_ef_bytes,
            self.total_ef_bytes as f64 / 1_000_000.0
        );
        println!(
            "  Partitioned EF:    {:>10} bytes ({:>6.2} MB)",
            self.total_pef_bytes,
            self.total_pef_bytes as f64 / 1_000_000.0
        );
        println!(
            "  Grouped EF:        {:>10} bytes ({:>6.2} MB)",
            self.total_gef_bytes,
            self.total_gef_bytes as f64 / 1_000_000.0
        );
        println!(
            "  VByte:             {:>10} bytes ({:>6.2} MB)",
            self.total_vbyte_bytes,
            self.total_vbyte_bytes as f64 / 1_000_000.0
        );
        println!(
            "  BP128:             {:>10} bytes ({:>6.2} MB)",
            self.total_bp128_bytes,
            self.total_bp128_bytes as f64 / 1_000_000.0
        );
        println!(
            "  BP32:              {:>10} bytes ({:>6.2} MB)",
            self.total_bp32_bytes,
            self.total_bp32_bytes as f64 / 1_000_000.0
        );
        println!();

        // Compute entropy
        let entropy = self.compute_entropy();
        let entropy_bytes = (entropy * self.total_postings as f64 / 8.0) as u64;

        let ef_ratio = self.total_input_bytes as f64 / self.total_ef_bytes as f64;
        let pef_ratio = self.total_input_bytes as f64 / self.total_pef_bytes as f64;
        let gef_ratio = self.total_input_bytes as f64 / self.total_gef_bytes as f64;
        let vbyte_ratio = self.total_input_bytes as f64 / self.total_vbyte_bytes as f64;
        let bp128_ratio = self.total_input_bytes as f64 / self.total_bp128_bytes as f64;
        let bp32_ratio = self.total_input_bytes as f64 / self.total_bp32_bytes as f64;
        let ef_bits = (self.total_ef_bytes * 8) as f64 / self.total_postings as f64;
        let pef_bits = (self.total_pef_bytes * 8) as f64 / self.total_postings as f64;
        let gef_bits = (self.total_gef_bytes * 8) as f64 / self.total_postings as f64;
        let vbyte_bits = (self.total_vbyte_bytes * 8) as f64 / self.total_postings as f64;
        let bp128_bits = (self.total_bp128_bytes * 8) as f64 / self.total_postings as f64;
        let bp32_bits = (self.total_bp32_bytes * 8) as f64 / self.total_postings as f64;

        println!("Compression (bits/posting):");
        println!(
            "  Entropy:   {:>5.2} bits/posting (theoretical lower bound, {:.2} MB)",
            entropy,
            entropy_bytes as f64 / 1_000_000.0
        );
        println!(
            "  Elias-Fano:{:>5.2} bits/posting ({:>5.2}x compression, {:.1}% of optimal)",
            ef_bits,
            ef_ratio,
            entropy / ef_bits * 100.0
        );
        println!(
            "  Part. EF:  {:>5.2} bits/posting ({:>5.2}x compression, {:.1}% of optimal)",
            pef_bits,
            pef_ratio,
            entropy / pef_bits * 100.0
        );
        println!(
            "  Grouped EF:{:>5.2} bits/posting ({:>5.2}x compression, {:.1}% of optimal)",
            gef_bits,
            gef_ratio,
            entropy / gef_bits * 100.0
        );
        println!(
            "  VByte:     {:>5.2} bits/posting ({:>5.2}x compression, {:.1}% of optimal)",
            vbyte_bits,
            vbyte_ratio,
            entropy / vbyte_bits * 100.0
        );
        println!(
            "  BP128:     {:>5.2} bits/posting ({:>5.2}x compression, {:.1}% of optimal)",
            bp128_bits,
            bp128_ratio,
            entropy / bp128_bits * 100.0
        );
        println!(
            "  BP32:      {:>5.2} bits/posting ({:>5.2}x compression, {:.1}% of optimal)",
            bp32_bits,
            bp32_ratio,
            entropy / bp32_bits * 100.0
        );
    }
}

fn main() -> std::io::Result<()> {
    let args: Vec<String> = env::args().collect();

    if args.len() < 2 {
        eprintln!("Usage: {} <input.docs> [--remap <mapping_file>]", args[0]);
        eprintln!();
        eprintln!("Encodes PISA posting lists with Elias-Fano encoding.");
        eprintln!();
        eprintln!("Options:");
        eprintln!("  --remap <file>  Remap document IDs using the specified mapping file");
        eprintln!("                  (generated by reorder_docids)");
        std::process::exit(1);
    }

    let input_path = &args[1];

    // Parse optional --remap argument
    let remap_path = args
        .iter()
        .position(|a| a == "--remap")
        .and_then(|i| args.get(i + 1));

    // Load mapping if provided
    let (mapping, subtree_ends) = if let Some(path) = remap_path {
        println!("Loading docid mapping from: {}", path);
        let (m, s) = load_mapping(path)?;
        println!("Loaded mapping for {} documents", m.len());
        (Some(m), Some(s))
    } else {
        (None, None)
    };

    println!("Reading PISA posting lists from: {}", input_path);
    if mapping.is_some() {
        println!("Document IDs will be remapped and transformed");
    }

    let file = File::open(input_path)?;
    let mut reader = BufReader::with_capacity(1024 * 1024, file);

    // Read header
    let header1 = read_u32(&mut reader)?;
    let header2 = read_u32(&mut reader)?;
    println!("Header: [{}, {}]", header1, header2);
    println!("Number of documents: {}", header2);
    let num_docs = header2 as usize;

    let mut stats = Stats::default();

    let start = Instant::now();
    let mut last_report = Instant::now();

    let mut orig_num_postings = 0;
    let mut remapped_num_postings = 0;

    // Read and encode all posting lists
    while let Some(mut postings) = read_posting_list(&mut reader)? {
        if postings.is_empty() {
            continue;
        }
        orig_num_postings += postings.len();

        // Remap document IDs if mapping is provided
        if let Some(ref m) = mapping {
            // Remap and sort
            for doc in postings.iter_mut() {
                *doc = m[*doc as usize];
            }
            postings.sort_unstable();
            let before = postings.len();
            postings.dedup();
            let after = postings.len();
            assert_eq!(before, after);

            // Apply range toggle transformation
            if let Some(ref ends) = subtree_ends {
                let before = postings.len();
                postings = transform_posting_list(&postings, num_docs, ends);
                let after = postings.len();
                if before == 1 {
                    assert!(after >= 1)
                }
            }
        }
        remapped_num_postings += postings.len();

        // Encode with Elias-Fano
        // let ef = EliasFano::new(postings.iter().copied(), max, len);
        stats.add_list(&postings);

        // Progress report every second
        if last_report.elapsed().as_secs() >= 1 {
            print!(
                "\rProcessed {:>10} lists, {:>12} postings...",
                stats.num_lists, stats.total_postings
            );
            std::io::stdout().flush()?;
            last_report = Instant::now();
        }
    }

    let elapsed = start.elapsed();
    println!(
        "\rProcessed {:>10} lists, {:>12} postings in {:.2}s",
        stats.num_lists,
        stats.total_postings,
        elapsed.as_secs_f64()
    );
    println!(
        "Original total postings: {:>12}, after remapping: {:>12}",
        orig_num_postings, remapped_num_postings
    );

    stats.print();

    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::io::Cursor;

    /// Helper to compute mapping and subtree_ends from in-memory data.
    /// Input: slice of (old_id, old_parent_id) in DFS order (new_id = index).
    fn compute_mapping_from_slice(data: &[(u32, u32)]) -> (Vec<u32>, Vec<u32>) {
        let num_docs = data.len();
        let mut old_to_new = vec![0u32; num_docs];
        let mut parents = vec![0u32; num_docs];

        for (new_id, &(old_id, old_parent)) in data.iter().enumerate() {
            old_to_new[old_id as usize] = new_id as u32;
            parents[new_id] = old_parent;
        }

        // Convert parents to new IDs
        for parent in &mut parents {
            *parent = old_to_new[*parent as usize];
        }

        // Compute subtree ranges
        let mut subtree_ends: Vec<u32> = (0..num_docs as u32).collect();

        for i in (1..num_docs).rev() {
            let u = i as u32;
            let p = parents[i];
            if p != u {
                if subtree_ends[u as usize] > subtree_ends[p as usize] {
                    subtree_ends[p as usize] = subtree_ends[u as usize];
                }
            }
        }

        (old_to_new, subtree_ends)
    }

    #[test]
    fn test_mapping_simple_chain() {
        // DFS order: 0 -> 1 -> 2 -> 3 (linear chain)
        // old_ids happen to match new_ids, each node's parent is the previous
        // new_id=0: old_id=0, parent=0 (root)
        // new_id=1: old_id=1, parent=0
        // new_id=2: old_id=2, parent=1
        // new_id=3: old_id=3, parent=2
        let data = [(0, 0), (1, 0), (2, 1), (3, 2)];
        let (old_to_new, subtree_ends) = compute_mapping_from_slice(&data);

        // old_to_new should be identity
        assert_eq!(old_to_new, vec![0, 1, 2, 3]);

        // subtree_ends:
        // Node 3: end=3 (leaf)
        // Node 2: end=max(2, end[3])=3
        // Node 1: end=max(1, end[2])=3
        // Node 0: end=max(0, end[1])=3
        assert_eq!(subtree_ends, vec![3, 3, 3, 3]);
    }

    #[test]
    fn test_mapping_binary_tree() {
        // Binary tree:
        //       0
        //      / \
        //     1   4
        //    / \
        //   2   3
        //
        // DFS order (pre-order): 0, 1, 2, 3, 4
        // new_id=0: old_id=0, parent=0 (root)
        // new_id=1: old_id=1, parent=0
        // new_id=2: old_id=2, parent=1
        // new_id=3: old_id=3, parent=1
        // new_id=4: old_id=4, parent=0
        let data = [(0, 0), (1, 0), (2, 1), (3, 1), (4, 0)];
        let (old_to_new, subtree_ends) = compute_mapping_from_slice(&data);

        // old_to_new should be identity
        assert_eq!(old_to_new, vec![0, 1, 2, 3, 4]);

        // subtree_ends:
        // Node 4: end=4 (leaf)
        // Node 3: end=3 (leaf)
        // Node 2: end=2 (leaf)
        // Node 1: end=max(1, end[2], end[3])=3
        // Node 0: end=max(0, end[1], end[4])=4
        assert_eq!(subtree_ends, vec![4, 3, 2, 3, 4]);
    }

    #[test]
    fn test_mapping_shuffled_old_ids() {
        // 5 nodes with shuffled old_ids:
        // Tree structure (in new_id space):
        //       0
        //      / \
        //     1   4
        //    / \
        //   2   3
        //
        // DFS order: new_id -> old_id
        // new_id=0: old_id=4
        // new_id=1: old_id=2
        // new_id=2: old_id=0
        // new_id=3: old_id=3
        // new_id=4: old_id=1
        //
        // Parents (in old_id space):
        // old_id=4 is root -> parent=4
        // old_id=2's parent is old_id=4
        // old_id=0's parent is old_id=2
        // old_id=3's parent is old_id=2
        // old_id=1's parent is old_id=4
        let data = [(4, 4), (2, 4), (0, 2), (3, 2), (1, 4)];
        let (old_to_new, subtree_ends) = compute_mapping_from_slice(&data);

        // old_to_new: old_id -> new_id
        // old_id=0 -> new_id=2
        // old_id=1 -> new_id=4
        // old_id=2 -> new_id=1
        // old_id=3 -> new_id=3
        // old_id=4 -> new_id=0
        assert_eq!(old_to_new, vec![2, 4, 1, 3, 0]);

        // subtree_ends (same tree structure as test_mapping_binary_tree):
        // Node 4: end=4 (leaf)
        // Node 3: end=3 (leaf)
        // Node 2: end=2 (leaf)
        // Node 1: end=max(1, end[2], end[3])=3
        // Node 0: end=max(0, end[1], end[4])=4
        assert_eq!(subtree_ends, vec![4, 3, 2, 3, 4]);
    }

    #[test]
    fn test_mapping_reordered() {
        // 4 nodes, but old_ids are reordered:
        // DFS new_id order: 0, 1, 2, 3
        // old_ids:          3, 1, 0, 2
        //
        // Tree structure (in new_id space):
        //       0
        //      / \
        //     1   3
        //     |
        //     2
        //
        // Parents (in old_id space):
        // new_id=0: old_id=3, parent=3 (root)
        // new_id=1: old_id=1, parent=3
        // new_id=2: old_id=0, parent=1
        // new_id=3: old_id=2, parent=3
        let data = [(3, 3), (1, 3), (0, 1), (2, 3)];
        let (old_to_new, subtree_ends) = compute_mapping_from_slice(&data);

        // old_to_new: old_id -> new_id
        // old_id=0 -> new_id=2
        // old_id=1 -> new_id=1
        // old_id=2 -> new_id=3
        // old_id=3 -> new_id=0
        assert_eq!(old_to_new, vec![2, 1, 3, 0]);

        // subtree_ends (in new_id space):
        // Node 3: end=3 (leaf)
        // Node 2: end=2 (leaf)
        // Node 1: parent=0, end=max(1, end[2])=2
        // Node 0: parent=0 (self), end=max(0, end[1], end[3])=3
        assert_eq!(subtree_ends, vec![3, 2, 2, 3]);
    }

    #[test]
    fn test_transform_simple() {
        // 4 documents with subtree_ends = [3, 2, 2, 3]
        // Tree:
        //       0
        //      / \
        //     1   3
        //     |
        //     2
        //
        // Posting list (in new space, sorted): [0, 2]
        //
        // i=0: is_present=true, state=false -> output 0, state=true, push end[0]=3
        // i=1: stack=[3], end=3 >= 1, no pop. is_present=false, state=true -> output 1, state=false, push end[1]=2
        // i=2: stack=[3,2], end=2 >= 2, no pop. is_present=true, state=false -> output 2, state=true, push end[2]=2
        // i=3: stack=[3,2,2], end=2 < 3, pop, state=false. end=2 < 3, pop, state=true. end=3 >= 3, stop.
        //      is_present=false, state=true -> output 3, state=false, push end[3]=3
        //
        // Output: [0, 1, 2, 3]
        let subtree_ends = vec![3, 2, 2, 3];
        let postings = vec![0, 2];
        let result = transform_posting_list(&postings, 4, &subtree_ends);
        assert_eq!(result, vec![0, 1, 2, 3]);
    }

    #[test]
    fn test_transform_full_subtree() {
        // 4 documents with subtree_ends = [3, 2, 2, 3]
        // Posting list (in new space, sorted): [0, 1, 2]
        // All of subtree under node 0's left child (1 and 2) are present, plus root
        //
        // i=0: is_present=true, state=false -> output 0, state=true, push 3
        // i=1: is_present=true, state=true -> no output
        // i=2: is_present=true, state=true -> no output
        // i=3: stack=[3], 3 >= 3, no pop. is_present=false, state=true -> output 3, state=false, push 3
        //
        // Output: [0, 3]
        let subtree_ends = vec![3, 2, 2, 3];
        let postings = vec![0, 1, 2];
        let result = transform_posting_list(&postings, 4, &subtree_ends);
        assert_eq!(result, vec![0, 3]);
    }

    #[test]
    fn test_transform_empty() {
        let subtree_ends = vec![3, 2, 2, 3];
        let postings: Vec<u32> = vec![];
        let result = transform_posting_list(&postings, 4, &subtree_ends);
        assert_eq!(result, vec![]);
    }

    #[test]
    fn test_transform_all_present() {
        // All documents present
        let subtree_ends = vec![3, 2, 2, 3];
        let postings = vec![0, 1, 2, 3];
        let result = transform_posting_list(&postings, 4, &subtree_ends);
        // i=0: present, state=false -> output 0, state=true, push 3
        // i=1: present, state=true -> no output
        // i=2: present, state=true -> no output
        // i=3: 3>=3 no pop. present, state=true -> no output
        // Output: [0]
        assert_eq!(result, vec![0]);
    }
}
